import React from "react";
import { motion } from "framer-motion";

const boxVariants = {
  hover: {
    backgroundColor: "#d9f0e7", // verde crema claro
    rotateY: 360,
    transition: { duration: 0.6 },
  },
  initial: {
    backgroundColor: "transparent",
    rotateY: 0,
    transition: { duration: 0.6 },
  },
};

const NosotrosSection = () => {
  return (
    <motion.section
      variants={boxVariants}
      initial="initial"
      whileHover="hover"
      style={{
        display: "flex",
        alignItems: "center",
        gap: "2rem",
        maxWidth: "1400px",
        margin: "0 auto 6rem",
        flexWrap: "wrap",
        padding: "1rem 2rem",
        borderRadius: "1rem",
        cursor: "pointer",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
      }}
    >
      <div style={{ flex: 1, minWidth: "320px" }}>
        <h1
          style={{
            fontSize: "3.5rem",
            fontWeight: "900",
            marginBottom: "1rem",
            color: "#003E73",
          }}
        >
          Nice to meet you
        </h1>
        <p
          style={{
            fontSize: "1.5rem",
            lineHeight: "1.8",
            color: "#003E73",
          }}
        >
          We're John and Jai, co-founders of Hydrant. Our journey started when both us
          (John, a scientist, and Jai, a finance consultant) were trying to solve the
          same problem on opposite sides of the US. After a friend connected us, the
          rest is history.
        </p>
      </div>

      <div
        style={{ flex: 1, minWidth: "320px", textAlign: "center" }}
      >
        <img
          src={require("../../assets/quien-contra-nosotros.jpg")}
          alt="Cargando..."
          style={{ maxWidth: "100%", borderRadius: "1rem", boxShadow: "0 0 15px rgba(0,0,0,0.15)" }}
        />
      </div>
    </motion.section>
  );
};

export default NosotrosSection;
